# Pre-query metadata filtering: narrow the search space before embedding
# For structured queries (date ranges, user IDs, document types), filtering on
# metadata before ANN search is faster than relying on semantic similarity alone.
# Build the metadata filter from the query using an LLM or rule-based extraction.

from langchain_openai import ChatOpenAI, OpenAIEmbeddings
from langchain_community.vectorstores import Chroma
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import JsonOutputParser
from langchain_core.documents import Document
import json

embeddings = OpenAIEmbeddings(model="text-embedding-3-small")
vectorstore = Chroma(persist_directory="./chroma_db", embedding_function=embeddings)
llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)


def extract_filters(question: str) -> dict:
    """
    Use an LLM to extract structured metadata filters from a natural language query.
    Returns a Chroma-compatible filter dict (MongoDB operators).
    Falls back to {} (no filter) if extraction fails.
    """
    prompt = ChatPromptTemplate.from_template(
        "Extract any structured filters from this question. "
        "Return a JSON object with zero or more of these keys: "
        "year (int), department (string), source (string). "
        "Return {{}} if no filters apply.\n\nQuestion: {question}"
    )
    try:
        chain = prompt | llm | JsonOutputParser()
        raw = chain.invoke({"question": question})
        # Convert plain values to Chroma $eq operators
        return {k: {"$eq": v} for k, v in raw.items() if v is not None}
    except Exception:
        return {}


def smart_retrieve(question: str, k: int = 6) -> list[Document]:
    """Combine extracted metadata filter with semantic query."""
    filters = extract_filters(question)
    print(f"Extracted filters: {filters}")
    return vectorstore.similarity_search(question, k=k, filter=filters if filters else None)


# "Find HR policies updated in 2024" → filter={year: {$eq: 2024}, department: {$eq: "HR"}}
results = smart_retrieve("What are the HR vacation policies from 2024?")
for doc in results[:3]:
    print(f"[{doc.metadata}] {doc.page_content[:80]}")

# Rule-based alternative: faster, no LLM call, but handles only known patterns
import re

def rule_based_filter(question: str) -> dict:
    filters = {}
    year_match = re.search(r"\b(20\d{2})\b", question)
    if year_match:
        filters["year"] = {"$eq": int(year_match.group(1))}
    if "HR" in question or "human resources" in question.lower():
        filters["department"] = {"$eq": "HR"}
    return filters
